public static long solve(long n, long[][] edges, String label) {
    int numNodes = (int) n;
    List<List<Integer>> graph = new ArrayList<>();
    for (int i = 0; i < numNodes; i++) {
        graph.add(new ArrayList<>());
    }
    for (long[] edge : edges) {
        int u = (int) edge[0];
        int v = (int) edge[1];
        graph.get(u).add(v);
        graph.get(v).add(u);
    }

    int maxLen = 0;
    for (int start = 0; start < numNodes; start++) {
        boolean[] visited = new boolean[numNodes];
        visited[start] = true;
        maxLen = Math.max(maxLen, dfs(start, graph, label, visited, String.valueOf(label.charAt(start))));
    }
    return maxLen;
}

