private static long dfs(int node, Set<Integer> visited, List<List<Integer>> graph, String label) {
    visited.add(node);
    long maxLen = 0;
    for (int neighbor : graph.get(node)) {
        if (!visited.contains(neighbor)) {
            long current = dfs(neighbor, new HashSet<>(visited), graph, label);
            if (current > maxLen) {
                maxLen = current;
            }
        }
    }

    // Check if current path can form a palindrome
    StringBuilder sb = new StringBuilder();
    for (int n : visited) {
        sb.append(label.charAt(n));
    }
    String path = sb.toString();
    if (isPalindrome(path)) {
        maxLen = Math.max(maxLen, path.length());
    }
    return maxLen;
}

