import java.util.*;

public class Solution {
    private static int maxLen = 0;

    public static long solve(long n, long[][] edges, String label) {
        maxLen = 0;
        int numNodes = (int) n;
        List<List<Integer>> graph = new ArrayList<>();
        for (int i = 0; i < numNodes; i++) {
            graph.add(new ArrayList<>());
        }
        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            graph.get(u).add(v);
            graph.get(v).add(u);
        }

        for (int i = 0; i < numNodes; i++) {
            dfs(graph, label, i, new boolean[numNodes], new StringBuilder());
        }

        return maxLen;
    }

    private static void dfs(List<List<Integer>> graph, String label, int node, boolean[] visited, StringBuilder current) {
        visited[node] = true;
        current.append(label.charAt(node));

        if (isPalindrome(current.toString())) {
            maxLen = Math.max(maxLen, current.length());
        }

        for (int neighbor : graph.get(node)) {
            if (!visited[neighbor]) {
                dfs(graph, label, neighbor, visited, current);
            }
        }

        current.deleteCharAt(current.length() - 1);
        visited[node] = false;
    }

    private static boolean isPalindrome(String s) {
        int left = 0;
        int right = s.length() - 1;
        while (left < right) {
            if (s.charAt(left) != s.charAt(right)) {
                return false;
            }
            left++;
            right--;
        }
        return true;
    }
}
